DROP TABLE IF EXISTS `activities`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `activities` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `main_equipment_id` bigint(20) unsigned NOT NULL,
  `activitable_type` varchar(255) NOT NULL,
  `activitable_id` bigint(20) unsigned NOT NULL,
  `activity_code` varchar(20) NOT NULL,
  `description` text DEFAULT NULL,
  `unit` varchar(50) DEFAULT NULL,
  `unit_price` decimal(12,2) DEFAULT NULL,
  `quantity` int(11) NOT NULL DEFAULT 1,
  `total_price` decimal(12,2) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `activities_main_equipment_id_foreign` (`main_equipment_id`),
  KEY `activities_activitable_type_activitable_id_index` (`activitable_type`,`activitable_id`),
  KEY `activities_activity_code_index` (`activity_code`),
  CONSTRAINT `activities_main_equipment_id_foreign` FOREIGN KEY (`main_equipment_id`) REFERENCES `main_equipments` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
