  `simcard_number` varchar(20) DEFAULT NULL COMMENT 'О“ГІВ¬О“Г¶ГұО“Г¶ГҝОҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»О“Г»в•ңО“Г¶ГҝОҙв”җВ»в”¬в•ң О“ГІВ¬О“Г¶Г©Оҙв”җВ»О“Г»в•ңОҙв”җВ»в”¬в•ңО“Г¶ГҝОҙв”җВ»в”¬в•ңОҙв”җВ»в•¬в•ңОҙв”җВ»в”¬в•ңОҙв”җВ»в”¬в•ңО“Г¶Г®О“Г®ГүО“ГІВ¬Оҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»О“Г»в•ңО“ГІВ¬Оҙв”җВ»в”¬в•ң',
