/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `equipment_locations` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `main_equipment_id` bigint(20) unsigned NOT NULL,
  `latitude` decimal(10,7) DEFAULT NULL COMMENT 'О“ГІВ¬О“ГІГәО“ГІВ¬Оҙв”җВ»О“Г»в•ңО“ГІВ¬О“ГІГі О“ГІВ¬Оҙв”җВ»в”¬в•ңО“ГІВ¬О“ГІГҰО“ГІВ¬Оҙв”җВ»О“Г»в•ңО“ГІВ¬Оҙв”җВ»в”¬в•ңО“Г¶ГҝОҙв”җВ»в”¬в•ңОҙв”җВ»О“Г»в•ңОҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»в”¬в•ңОҙв”җВ»О“Г»в•ңОҙв”җВ»в”¬в•ңОҙв”җВ»О“Г»в•ңОҙв”җВ»в”¬в•ң',
  `longitude` decimal(10,7) DEFAULT NULL COMMENT 'О“ГІВ¬О“ГІГ»О“Г¶ГҝОҙв”җВ»в”¬в•ңО“Г¶ГҝОҙв”җВ»в”¬в•ң О“ГІВ¬Оҙв”җВ»в”¬в•ңО“ГІВ¬О“ГІГҰО“ГІВ¬Оҙв”җВ»О“Г»в•ңО“ГІВ¬Оҙв”җВ»в”¬в•ңО“Г¶ГҝОҙв”җВ»в”¬в•ңОҙв”җВ»О“Г»в•ңОҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»в”¬в•ңОҙв”җВ»О“Г»в•ңОҙв”җВ»в”¬в•ңОҙв”җВ»О“Г»в•ңОҙв”җВ»в”¬в•ң',
  `address` text DEFAULT NULL COMMENT 'О“ГІВ¬Оҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»О“Г»в•ңО“ГІВ¬О“Г¶Г© О“Г¶ГҝОҙв”җВ»в”¬в•ңО“ГІВ¬О“ГІГӯО“ГІВ¬Оҙв”җВ»в”¬в•ң',
  `cabinet_initial_height` decimal(5,2) DEFAULT NULL COMMENT 'О“ГІВ¬Оҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»О“Г»в•ңО“ГІВ¬Оҙв”җВ»в”¬в•ңО“Г¶ГҝОҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»в”¬в•ңО“ГІВ¬О“ГІГә О“ГІВ¬Оҙв”җВ»в”¬в•ңО“Г¶ГҝОҙв”җВ»в”¬в•ңО“Г¶ГҝОҙв”җВ»в”¬в•ңОҙв”җВ»О“Г»в•ңОҙв”җВ»в”¬в•ңО“Г¶ГҝОҙв”җВ»в”¬в•ң О“ГІВ¬Оҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»в”¬в•ңО“Г¶ГҝОҙв”җВ»в”¬в•ңО“Г¶ГҝОҙв”җВ»в”¬в•ң (О“Г¶ГҝОҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»О“Г»в•ң)',
  `cabinet_final_height` decimal(5,2) DEFAULT NULL COMMENT 'О“ГІВ¬Оҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»О“Г»в•ңО“ГІВ¬Оҙв”җВ»в”¬в•ңО“Г¶ГҝОҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»в”¬в•ңО“ГІВ¬О“ГІГә О“Г¶ГҝОҙв”җВ»в”¬в•ңО“Г¶ГҝОҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»в”¬в•ңОҙв”җВ»О“Г»в•ңОҙв”җВ»в”¬в•ңОҙв”җВ»О“Г»в•ңОҙв”җВ»в”¬в•ң О“ГІВ¬Оҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»в”¬в•ңО“Г¶ГҝОҙв”җВ»в”¬в•ңО“Г¶ГҝОҙв”җВ»в”¬в•ң (О“Г¶ГҝОҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»в”¬в•ңО“ГІВ¬Оҙв”җВ»О“Г»в•ң)',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `equipment_locations_main_equipment_id_index` (`main_equipment_id`),
  KEY `equipment_locations_latitude_longitude_index` (`latitude`,`longitude`),
  CONSTRAINT `equipment_locations_main_equipment_id_foreign` FOREIGN KEY (`main_equipment_id`) REFERENCES `main_equipments` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=256 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

