CREATE TABLE `main_equipments` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `inspection_id` bigint(20) unsigned NOT NULL,
  `main_equipment_type_id` bigint(20) unsigned NOT NULL,
  `scada_code` varchar(4) DEFAULT NULL,
  `brand_id` bigint(20) unsigned DEFAULT NULL,
  `post_id` bigint(20) unsigned DEFAULT NULL,
  `latitude` decimal(10,7) DEFAULT NULL,
  `longitude` decimal(10,7) DEFAULT NULL,
  `height` int(11) DEFAULT NULL,
  `installation_type` varchar(50) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `equipments_data` longtext DEFAULT NULL CHECK (json_valid(`equipments_data`)),
  `department_id` bigint(20) unsigned DEFAULT NULL,
  `communication_id` bigint(20) unsigned DEFAULT NULL,
  `simcard_type_id` bigint(20) unsigned DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `main_equipments_inspection_id_index` (`inspection_id`),
  KEY `main_equipments_main_equipment_type_id_index` (`main_equipment_type_id`),
  KEY `main_equipments_post_id_index` (`post_id`),
  KEY `main_equipments_department_id_foreign` (`department_id`),
  KEY `fk_main_equipment_communication` (`communication_id`),
  KEY `fk_main_equipment_simcard` (`simcard_type_id`),
  CONSTRAINT `fk_main_equipment_communication` FOREIGN KEY (`communication_id`) REFERENCES `communications` (`id`),
  CONSTRAINT `fk_main_equipment_simcard` FOREIGN KEY (`simcard_type_id`) REFERENCES `simcard_types` (`id`),
  CONSTRAINT `main_equipments_department_id_foreign` FOREIGN KEY (`department_id`) REFERENCES `departments` (`id`) ON DELETE SET NULL,
  CONSTRAINT `main_equipments_inspection_id_foreign` FOREIGN KEY (`inspection_id`) REFERENCES `inspections` (`id`) ON DELETE CASCADE,
  CONSTRAINT `main_equipments_main_equipment_type_id_foreign` FOREIGN KEY (`main_equipment_type_id`) REFERENCES `main_equipment_types` (`id`) ON DELETE CASCADE,
  CONSTRAINT `main_equipments_post_id_foreign` FOREIGN KEY (`post_id`) REFERENCES `posts` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=343 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
